How-To-Repeat: You can use this script to repeat the problem:

#!/usr/local/bin/perl
use strict;

my $iterations = 50;
my $dirs = 1000;

mkdir 'src';

for(1..$iterations)
{
  print "Iterations $_\n";
  do_test();
}

sub do_test
{
  print "Creating $dirs sample directories...\n";

  for(1..$dirs)
  {
    my $dirname = `mktemp -d src/XXXXX`;
    chomp $dirname;
    system("touch $dirname/data && touch $dirname/meta");
    print "$_ ";
    }

    print "done\n";

    my ($pid1, $pid2) = (do_job('src', 'dst1'), do_job('src', 'dst2'));
    waitpid($pid1, 0);
    waitpid($pid2, 0);
}

sub do_job
{
  my ($src, $dst) = @_;

  my $pid = fork();
  return $pid if $pid != 0;

  system("mkdir -p $dst && ls $src | xargs -I _ mv -n $src/_ $dst");
  system("rm -rf $dst/*") == 0 or die;

  exit(0);
}
